<?php get_header();
global $post;

$categories = get_the_category();
$category_slug = !empty($categories)
    ? nurofen_get_translated_category_slug($categories[0]->slug)
    : '';

$args = [
    'post_type' => 'post',
    'posts_per_page' => '-1',
    'post__not_in' => [get_the_ID()],
];

if ($category_slug) {
    $args['tax_query'] = [
        [
            'taxonomy' => 'category',
            'field' => 'slug',
            'terms' => $category_slug,
        ],
    ];
}

$current_category_posts = new WP_Query($args);
?>


<main>


    <?php
    while (have_posts()):
        the_post();

        $type = get_field('content_type');
        $logo = get_field('article_logo'); ?>

        <section class="article-main">
            <div class="wrapper">
                <?php if ($logo): ?>
                    <div class="logotip-article">
                        <?php if (is_array($logo)): ?>
                            <img src="<?= esc_url($logo['url']); ?>" alt="<?= esc_attr($logo['alt'] ?? ''); ?>">
                        <?php elseif (is_numeric($logo)): ?>
                            <img src="<?= esc_url(wp_get_attachment_image_url((int) $logo, 'full')); ?>" alt="">
                        <?php endif; ?>
                    </div>
                <?php endif; ?>

                <?php if ($type === 'video'): ?>
                    <?php
                    $video_article = get_field('video-article') ?: [];
                    $video_url = $video_article['video_url'] ?? '';
                    $text = $video_article['video_text'] ?? '';
                    $person_photo = $video_article['person_photo'] ?? null;
                    $person_name = $video_article['person_name'] ?? '';
                    $person_desc = $video_article['person_description'] ?? '';
                    $card_img = get_field('card_img');
                    ?>

                    <div class="block-video">
                        <?php if ($video_url && $card_img): ?>
                            <a href="<?= esc_url(get_video_embed_url($video_url)); ?>" class="image-video-article" data-fancybox
                                data-type="iframe">
                                <img src="<?= esc_url($card_img['url']) ?>" alt="<?= esc_attr($card_img['alt'] ?? '') ?>">
                                <div class="button-play-article">
                                    <?php require get_template_directory() . '/inc/play-button-svg.php'; ?>
                                </div>
                            </a>
                        <?php endif; ?>
                        <div class="info-about-article">
                            <div class="about-article">
                                <span class="icon-article"><?php esc_html_e('Видео', NUROFEN_TD); ?></span>
                                <span class="title-article color-">
                                    <?php the_title(); ?>
                                </span>
                                <?php if ($text): ?>
                                    <span>
                                        <?= $text; ?>
                                    </span>
                                <?php endif; ?>
                            </div>

                            <?php if ($person_photo): ?>
                                <div class="about-person-info">

                                    <div class="image-elipse-person">
                                        <img src="<?= $person_photo['url']; ?>" alt="<?= $person_photo['alt']; ?>">
                                    </div>


                                    <div class="text-about-person">
                                        <?php if ($person_name): ?>
                                            <span class="name">
                                                <?= $person_name; ?>
                                            </span>
                                        <?php endif; ?>

                                        <?php if ($person_desc): ?>
                                            <span>
                                                <?= $person_desc; ?>
                                            </span>
                                        <?php endif; ?>
                                    </div>
                                </div>
                            <?php endif; ?>

                        </div>

                    </div>

                <?php else: ?>

                    <div class="block-article-text">
                        <span class="icon-article"><?php esc_html_e('Статья', NUROFEN_TD); ?></span>
                        <h2>
                            <?php the_title(); ?>
                        </h2>
                        <div class="article-content">
                            <?php the_content(); ?>
                        </div>
                    </div>

                <?php endif; ?>


            </div>
        </section>

    <?php endwhile; ?>
